const userText = msg.payload;
msg.payload = {
  input: {
    brief:
      "Classify this request and extract slots. Return your structured answer as an " +
      "artifact with fields: proceed (boolean — true only if this is a weather-activity " +
      "question), location (string), timeframe (string), activity (string). If it is not " +
      "a weather-activity question, set proceed=false. Request: \"" + userText + "\"",
    context: [
      { slug: 'user-request', binding: 'context_inline', content: String(userText) }
    ],
    execution: { workspace: 'none' },
    successCriteria: {
      version: 1,
      gates: [
        {
          id: 'submit-output',
          kind: 'submit-tool-call',
          description: 'Call submit_freeform_output once with the structured slots.',
          required: true
        }
      ]
    }
  }
};
return msg;

// Freeform artifacts are { kind, title, body } where `body` holds the inline
// content (a JSON string for kind:'json'). Extract the first artifact's body,
// falling back to the summary if the agent inlined JSON there instead.
function extractJson(state) {
  const arts = Array.isArray(state.artifacts) ? state.artifacts : [];
  for (const art of arts) {
    if (!art || typeof art !== 'object') continue;
    if (typeof art.body === 'string') {
      try { return JSON.parse(art.body); } catch (e) { /* not JSON, keep looking */ }
    }
  }
  if (typeof state.summary === 'string') {
    const m = state.summary.match(/\{[\s\S]*\}/);
    if (m) { try { return JSON.parse(m[0]); } catch (e) {} }
  }
  return {};
}
const state = (msg.payload && msg.payload.state) || {};
const slots = extractJson(state);
msg.intent = slots;
msg.intentTaskId = msg.payload && msg.payload.taskId;
msg.intentOutputCid = msg.payload && msg.payload.attempt && msg.payload.attempt.outputCid;
msg.proceed = slots.proceed === true;
return msg;

// Geocoding is out of scope for the demo: a tiny lookup table, default Lyon.
const COORDS = { lyon: [45.76, 4.84], paris: [48.85, 2.35], london: [51.51, -0.13], berlin: [52.52, 13.40] };
const key = String((msg.intent && msg.intent.location) || 'lyon').toLowerCase();
const [lat, lon] = COORDS[key] || COORDS.lyon;
msg.url =
  'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon +
  '&daily=temperature_2m_max,precipitation_probability_max&forecast_days=7&timezone=auto';
return msg;

const forecast = msg.payload; // http response object
msg.payload = {
  input: {
    brief:
      "Given this 7-day forecast and the user's activity, recommend the best day(s) with " +
      "concrete reasoning (temperature, rain probability), or advise against if the weather " +
      "is poor. Be specific about which day and why.",
    context: [
      { slug: 'intent', binding: 'context_inline', content: JSON.stringify(msg.intent || {}) },
      { slug: 'forecast', binding: 'context_inline', content: JSON.stringify(forecast || {}).slice(0, 60000) }
    ],
    execution: { workspace: 'none' }
  },
  references: msg.intentOutputCid ? [{ taskId: msg.intentTaskId, outputCid: msg.intentOutputCid, role: 'context' }] : []
};
return msg;

const advisor = msg.payload && msg.payload.state ? msg.payload.state : {};
msg.advisorTaskId = msg.payload && msg.payload.taskId;
msg.recommendation = advisor.summary; // carry past the JUDGE payload overwrite
const advisorOutputCid = msg.payload && msg.payload.attempt && msg.payload.attempt.outputCid;
msg.payload = {
  input: {
    brief:
      "Evaluate the weather recommendation against the rubric. Return an artifact with " +
      "fields: pass (boolean), score (0-1), notes (string). pass=true only if the advice is " +
      "sound, matches the forecast, and is actionable.",
    context: [
      { slug: 'recommendation', binding: 'context_inline', content: String(advisor.summary || 'n/a') }
    ],
    execution: { workspace: 'none' },
    successCriteria: {
      version: 1,
      gates: [
        {
          id: 'submit-output',
          kind: 'submit-tool-call',
          description: 'Call submit_freeform_output once with the verdict.',
          required: true
        }
      ]
    }
  },
  references: advisorOutputCid ? [{ taskId: msg.advisorTaskId, outputCid: advisorOutputCid, role: 'judged_work' }] : []
};
return msg;

// Same extraction as the intent parser: read the first artifact's `body`
// (JSON string), falling back to a JSON blob in the summary.
function extractJson(state) {
  const arts = Array.isArray(state.artifacts) ? state.artifacts : [];
  for (const art of arts) {
    if (!art || typeof art !== 'object') continue;
    if (typeof art.body === 'string') {
      try { return JSON.parse(art.body); } catch (e) { /* not JSON, keep looking */ }
    }
  }
  if (typeof state.summary === 'string') {
    const m = state.summary.match(/\{[\s\S]*\}/);
    if (m) { try { return JSON.parse(m[0]); } catch (e) {} }
  }
  return {};
}
const state = (msg.payload && msg.payload.state) || {};
const verdict = extractJson(state);
msg.verdict = verdict;
msg.pass = verdict.pass === true;
return msg;
